// Extract fill level from JSON payload
let fill = msg.payload.fill_level;
let status = "Normal";

// Status classification rules
if (fill > 80) {
    status = "Critical";
} else if (fill > 50) {
    status = "Warning";
}

// Add status field to the payload object
msg.payload.status = status;
return msg;

let p = msg.payload;

// Safely format parameters into SQL query
msg.topic = `INSERT INTO waste_data (bin_id, fill_level, weight, latitude, longitude, timestamp, status) VALUES ('${p.bin_id}', ${p.fill_level}, ${p.weight}, ${p.latitude}, ${p.longitude}, '${p.timestamp}', '${p.status}');`;
return msg;

// Fetch global flow state or initialize default
let bins = flow.get('bins') || {};
let totalRecords = flow.get('totalRecords') || 0;

let p = msg.payload;
bins[p.bin_id] = p; // Update status/state of current bin
totalRecords += 1;  // Increment total telemetry packets received

// Save updated states back to flow memory
flow.set('bins', bins);
flow.set('totalRecords', totalRecords);

// Count bins based on status thresholds
let normal = 0;
let warning = 0;
let critical = 0;

for (let id in bins) {
    let status = bins[id].status;
    if (status === "Normal") normal++;
    else if (status === "Warning") warning++;
    else if (status === "Critical") critical++;
}

let totalBins = Object.keys(bins).length;

// Return array of outputs, mapped to widgets
return [
    { payload: totalBins },
    { payload: normal },
    { payload: warning },
    { payload: critical },
    { payload: totalRecords },
    { payload: p.timestamp }
];

let bins = flow.get('bins') || {};
let tableData = [];
for (let id in bins) {
    let status = bins[id].status || 'Normal';
    let statusHTML = `<span class="status-pill ${status.toLowerCase()}">${status}</span>`;
    tableData.push({
        "Bin ID": bins[id].bin_id,
        "Fill Level (%)": bins[id].fill_level,
        "Weight (kg)": bins[id].weight,
        "Status": statusHTML
    });
}

// Sort alphabetical by Bin ID
tableData.sort((a, b) => a["Bin ID"].localeCompare(b["Bin ID"]));
msg.payload = tableData;
return msg;

let p = msg.payload;

// Choose marker pin color based on fill status
let color = "green";
if (p.status === "Warning") {
    color = "orange";
} else if (p.status === "Critical") {
    color = "red";
}

// Construct marker payload structure for worldmap node
msg.payload = {
    name: p.bin_id,
    lat: p.latitude,
    lon: p.longitude,
    icon: "trash",
    iconColor: "white",
    markerColor: color,
    layer: "Garbage Bins",
    popup: `<b>${p.bin_id}</b><br>Fill Level: ${p.fill_level}%<br>Weight: ${p.weight} kg<br>Status: ${p.status}`
};
return msg;

// Set series line label as Bin ID, data as value
msg.topic = msg.payload.bin_id;
msg.payload = msg.payload.fill_level;
return msg;

msg.topic = msg.payload.bin_id;
msg.payload = msg.payload.weight;
return msg;

let p = msg.payload;
let cities = {
    "BIN001": "Pune (Kothrud)",
    "BIN002": "Pune (Koregaon Park)",
    "BIN003": "Pune (Shivajinagar)",
    "BIN004": "Pune (Viman Nagar)",
